// LoadCountConversationChatMessages loads the count of ConversationChatMessages for a slice in a single batch query
func (os ChatConversationSlice) LoadCountConversationChatMessages(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// Build the IN arg expression from parent PKs

	pkID := make(pgtypes.Array[int64], 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		pkID = append(pkID, o.ID)
	}
	PKArgExpr := psql.Select(sm.Columns(
		psql.F("unnest", psql.Cast(psql.Arg(pkID), "bigint[]")),
	))

	// countResult holds one scanned row from the batch count query.
	// FK columns are aliased to the parent PK column names for direct map lookup.
	type countResult struct {
		ID    int64
		Count int64
	}

	batchMods := []bob.Mod[*dialect.SelectQuery]{
		// SELECT fk AS parent_pk, count(*)
		sm.Columns(
			ChatMessages.Columns.ConversationID.As("id"),
			psql.Raw("count(*) as count"),
		),
		// Single-hop: FROM related table directly
		sm.From(ChatMessages.NameAs()),

		// WHERE fk IN (parent PKs)
		sm.Where(ChatMessages.Columns.ConversationID.OP("IN", PKArgExpr)),
		// GROUP BY fk columns
		sm.GroupBy(ChatMessages.Columns.ConversationID),
	}
	batchMods = append(batchMods, mods...)

	results, err := bob.All(ctx, exec,
		psql.Select(batchMods...),
		scan.StructMapper[countResult](),
	)
	if err != nil {
		return err
	}

	// Single-column FK: direct map lookup
	countMap := make(map[int64]int64, len(results))
	for _, r := range results {
		countMap[r.ID] = r.Count
	}
	for _, o := range os {
		if o == nil {
			continue
		}
		count := countMap[o.ID]
		o.C.ConversationChatMessages = &count
	}

	return nil
}

type chatConversationJoins[Q dialect.Joinable] struct {
	typ                      string
	Connection               modAs[Q, connectionColumns]
	User                     modAs[Q, userColumns]
	ConversationChatMessages modAs[Q, chatMessageColumns]
}

func (j chatConversationJoins[Q]) aliasedAs(alias string) chatConversationJoins[Q] {
	return buildChatConversationJoins[Q](buildChatConversationColumns(alias), j.typ)
}

func buildChatConversationJoins[Q dialect.Joinable](cols chatConversationColumns, typ string) chatConversationJoins[Q] {
	return chatConversationJoins[Q]{
		typ: typ,
		Connection: modAs[Q, connectionColumns]{
			c: Connections.Columns,
			f: func(to connectionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Connections.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ConnectionID),
					))
				}

				return mods
			},
		},
		User: modAs[Q, userColumns]{
			c: Users.Columns,
			f: func(to userColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Users.Name().As(to.Alias())).On(
						to.ID.EQ(cols.UserID),
					))
				}

				return mods
			},
		},
		ConversationChatMessages: modAs[Q, chatMessageColumns]{
			c: ChatMessages.Columns,
			f: func(to chatMessageColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, ChatMessages.Name().As(to.Alias())).On(
						to.ConversationID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
